#include <bits/stdc++.h>
using namespace std;

const int N=5e4+10;

int l,s,t,m,p[N],f[N],b[N];

int main(){
    scanf("%d%d%d%d",&l,&s,&t,&m);
    for(int i=1;i<=m;i++)
        scanf("%d",&p[i]);
    sort(p+1,p+m+1);
    if(s==t){
        int ans=0;
        for(int i=1;i<=m;i++)
            if(p[i]%s==0)
                ans++;
        printf("%d",ans);
        return 0;
    }
    for(int i=m;i;i--)
        p[i]-=p[i-1];
    for(int i=1;i<=m;i++)
        p[i]=min(p[i],2*s*s);
    for(int i=1;i<=m;i++){
        p[i]+=p[i-1];
        b[p[i]]++;
    }
    l=p[m]+2*s*s;
    memset(f,0x3f,sizeof(f));
    f[0]=0;
    deque<int> q;
    for(int i=s;i<=l;i++){
        while(q.size() && q.front()<i-t)
            q.pop_front();
        while(q.size() && f[q.back()]>f[i-s])
            q.pop_back();
        q.push_back(i-s);
        f[i]=f[q.front()]+b[i];
    }
    printf("%d",f[l]);
    return 0;
}
